import {
  createChatChannelPlugin,
  getChatChannelMeta,
  DEFAULT_ACCOUNT_ID,
} from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { getPulseBoardRuntime } from "./runtime.js";
import type { PulseBoardConfig } from "./types.js";

const DEFAULT_PULSEBOARD_ACCOUNT_ID = DEFAULT_ACCOUNT_ID;

type ResolvedPulseBoardAccount = {
  accountId: string;
  name: string;
  enabled: boolean;
  configured: boolean;
  boardUrl: string;
  apiToken: string;
  username: string;
};

function resolvePulseBoardAccount(cfg: Record<string, unknown>): ResolvedPulseBoardAccount {
  const channels = cfg.channels as Record<string, unknown> | undefined;
  const section = channels?.pulseboard as Record<string, unknown> | undefined;
  return {
    accountId: DEFAULT_PULSEBOARD_ACCOUNT_ID,
    name: (section?.name as string) ?? "default",
    enabled: section?.enabled !== false,
    configured: Boolean(section?.boardUrl && section?.apiToken),
    boardUrl: (section?.boardUrl as string) ?? "",
    apiToken: (section?.apiToken as string) ?? "",
    username: (section?.username as string) ?? "",
  };
}

